$ /bin/bash -lc "cd /home/andy/ads && node - <<'NODE'
import Database from 'better-sqlite3';

const db = new Database('.ads/ads.db', { readonly: true, fileMustExist: true });

const keywords = ['brain', 'ingest', 'runner', 'jules', 'automationmode'];

const rows = db
  .prepare(
    "'`SELECT conversation_id, COUNT(*) AS hits, MIN(created_at) AS first_ts, MAX(created_at) AS last_ts
     FROM conversation_messages
     WHERE ${keywords.map(() => `lower(content) LIKE ?`).join('"' OR ')}
     GROUP BY conversation_id
     ORDER BY hits DESC, last_ts DESC
     LIMIT 20"'`
  )
  .all(...keywords.map((k) => `%${k}%`));

console.log(JSON.stringify(rows, null, 2));
NODE'

