$ /bin/bash -lc "cd /home/andy/ads && node - <<'NODE'
import Database from 'better-sqlite3';

const db = new Database('.ads/state.db', { readonly: true, fileMustExist: true });

const keyword = 'runner';
const rows = db
  .prepare(
    "'`SELECT namespace, session_id, COUNT(*) AS n,
            MIN(ts) AS first_ts, MAX(ts) AS last_ts
     FROM history_entries
     WHERE lower(text) LIKE ?
     GROUP BY namespace, session_id
     ORDER BY last_ts DESC
     LIMIT 20`
  )
  .all(`%${keyword}%`);

console.log(
  rows.map((r) => ({
    namespace: r.namespace,
    session_id: r.session_id,
    n: r.n,
    first_iso: new Date(r.first_ts).toISOString(),
    last_iso: new Date(r.last_ts).toISOString(),
  }))
);
